// Build a compact text representation of alerts and clusters for the AI prompt.
// Limits token usage by truncating long summaries.
// Source names are included when available to support source-aware summary generation.
const ctx = $input.first().json;

const topAlerts = (ctx.alerts || []).slice(0, 20).map((a, i) => {
  const sourceNote = a.source_name ? ` [source: ${a.source_name}]` : '';
  return `${i + 1}. [importance=${a.importance_score}] ${a.headline}${a.summary_text ? ' — ' + a.summary_text.slice(0, 150) : ''}${sourceNote}`;
}).join('\n');

const clusterText = (ctx.clusters || []).map(c =>
  `- ${c.cluster_label} (${c.alert_count} alerts, importance=${c.importance_score})${c.summary_text ? ': ' + c.summary_text.slice(0, 150) : ''}`
).join('\n');

return [{
  json: {
    ...ctx,
    _prompt_alerts: topAlerts,
    _prompt_clusters: clusterText || '(no clusters identified)'
  }
}];

