// Parse and validate the AI summary output against the daily_summary schema.
const rawContent = $input.first().json?.message?.content
  || $input.first().json?.choices?.[0]?.message?.content
  || '';
const ctx = $('Build Prompt Context').first().json;

const VALID_SENTIMENTS = ['bullish', 'bearish', 'neutral', 'mixed'];
const VALID_SOURCE_ROLES = ['primary', 'confirmation', 'data', 'commentary', 'official'];

let summary;
try {
  const cleaned = rawContent.replace(/^```[a-z]*\n?|\n?```$/g, '').trim();
  summary = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse AI summary JSON for ${ctx.topic_slug}/${ctx.date_key}: ${e.message}. Raw: ${rawContent.slice(0, 200)}`);
}

// Validate required fields
if (!summary.headline || summary.headline.length < 10) {
  throw new Error('AI summary missing or too short headline');
}
if (!summary.overview || summary.overview.length < 100) {
  throw new Error('AI summary missing or too short overview');
}
if (!Array.isArray(summary.key_events) || summary.key_events.length === 0) {
  throw new Error('AI summary missing key_events');
}
if (!VALID_SENTIMENTS.includes(summary.sentiment)) {
  summary.sentiment = 'neutral';
}
if (typeof summary.topic_score !== 'number') {
  summary.topic_score = 50;
}

// Helper: normalize a source reference array
function normalizeSources(arr, maxItems) {
  if (!Array.isArray(arr) || arr.length === 0) return null;
  const normalized = arr.slice(0, maxItems).map(s => ({
    source_name: String(s.source_name || '').slice(0, 200),
    source_url: s.source_url ? String(s.source_url).slice(0, 2000) : null,
    source_role: VALID_SOURCE_ROLES.includes(s.source_role) ? s.source_role : null
  })).filter(s => s.source_name.length > 0);
  return normalized.length > 0 ? normalized : null;
}

// Clamp scores and normalize key_events (including per-event sources)
summary.topic_score = Math.min(100, Math.max(0, Math.round(summary.topic_score)));
summary.key_events = summary.key_events.slice(0, 7).map(e => ({
  title: String(e.title || '').slice(0, 150),
  significance: String(e.significance || '').slice(0, 300),
  importance_score: Math.min(100, Math.max(0, Math.round(e.importance_score || 0))),
  sources: normalizeSources(e.sources, 5)
}));

// Normalize top-level source fields
summary.sources = normalizeSources(summary.sources, 10);
summary.source_confidence_note = summary.source_confidence_note
  ? String(summary.source_confidence_note).slice(0, 400)
  : null;

// Return the aggregate context with the validated summary attached
// Strip internal prompt fields before passing downstream
const { _prompt_alerts, _prompt_clusters, ...cleanCtx } = ctx;
return [{ json: { ...cleanCtx, summary } }];
